158→// ── Main ──────────────────────────────────────────────────────────
159→export default function Home() {
160→  const [messages, setMessages] = useState<Msg[]>([]);
161→  const [animatingIdx, setAnimatingIdx] = useState<number>(-1);
162→  const [input, setInput] = useState("");
163→  const [error, setError] = useState<string | null>(null);
164→  const [canvasState, setCanvasState] = useState<CanvasState>("idle");
165→  const [latestOmega, setLatestOmega] = useState("");
166→  const [showPill, setShowPill] = useState(false);
167→  const [statusText, setStatusText] = useState<string | null>(null);
168→  const textareaRef = useRef<HTMLTextAreaElement>(null);
169→  const feedRef = useRef<HTMLDivElement>(null);
170→  const [sessionId, setSessionId] = useState<string | null>(null);
171→  const [historyOpen, setHistoryOpen] = useState(false);
172→  const [sessionList, setSessionList] = useState<{id: string; created_at: string; preview: string}[]>([]);
173→
174→  const bottomRef = useRef<HTMLDivElement>(null);
175→  const inChatMode = messages.length > 0;
176→
177→  useEffect(() => {
178→    const handleKeyDown = (e: KeyboardEvent) => {
179→      if (e.key === "Escape") setHistoryOpen(false);
180→    };
181→    window.addEventListener("keydown", handleKeyDown);
182→    return () => window.removeEventListener("keydown", handleKeyDown);
183→  }, []);
184→
185→  useEffect(() => {
186→    if (historyOpen) {
187→      fetch('/api/sessions').then(res => res.json()).then(data => {
188→        if (Array.isArray(data)) setSessionList(data);
189→      }).catch(console.error);
190→    }
191→  }, [historyOpen]);
192→
193→  const loadSession = async (id: string) => {
194→    try {
195→      const res = await fetch(`/api/sessions/${id}`);
196→      const data = await res.json();
197→      if (Array.isArray(data)) {
198→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
199→        setMessages(data.map((m: any) => ({ role: m.role, text: m.content, timestamp: m.created_at })));
200→        setSessionId(id);
