469→                  <button type="button" className={s.attachBtn} aria-label="Attach file" disabled={canvasState === "thinking"}>
470→                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{opacity: 0.6}}><path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"/></svg>
471→                  </button>
472→                  <textarea
473→                    ref={textareaRef}
474→                    className={s.textarea}
475→                    value={input}
476→                    onChange={e => { setInput(e.target.value); autoResize(); }}
477→                    onKeyDown={handleKey}
478→                    placeholder="Ask OmegA anything…"
479→                    rows={1}
480→                    disabled={canvasState === "thinking"}
481→                    autoFocus
482→                  />
483→                  {input.length > 200 && (
484→                    <div className={s.charCount}>{input.length}</div>
485→                  )}
486→                  <button
487→                    className={`${s.sendBtn} ${input.trim() ? s.pulse : ''}`}
488→                    type="submit"
489→                    disabled={!input.trim() || canvasState === "thinking"}
490→                    aria-label="Send message"
491→                  >
492→                    Ω
493→                  </button>
494→                </div>
495→              </form>
496→            </div>
497→          </>
498→        )}
499→      </div>
500→
501→      {/* History Panel */}
502→      {historyOpen && <div className={s.historyOverlay} onClick={() => setHistoryOpen(false)} />}
503→      <div className={`${s.historyPanel} ${historyOpen ? s.open : ""}`}>
504→        <div className={s.historyPanelHeader}>
505→          <span>Session History</span>
506→          <button onClick={startNewSession}>+ New</button>
