'use client';

import s from './UserMessage.module.css';

interface UserMessageProps {
  text: string;
  timestamp?: string;
}

export default function UserMessage({ text, timestamp }: UserMessageProps) {
  return (
    <div className={s.wrap}>
      <div className={s.bubble}>{text}</div>
      {timestamp && (
        <div className={s.timestamp}>
          {new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </div>
      )}
    </div>
  );
}

.wrap {
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  padding: 0 1.5rem;
  margin-bottom: 1rem;
  animation: fadeUp 0.35s cubic-bezier(0.22, 1, 0.36, 1) both;
}

@keyframes fadeUp {
  from {
    opacity: 0;
    transform: translateY(12px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.bubble {
  max-width: 72%;
  padding: 0.85rem 1.15rem;
  border-radius: 1.25rem 1.25rem 0.25rem 1.25rem;
  background: rgba(6, 6, 22, 0.82);
  border: 1px solid rgba(99, 102, 241, 0.22);
  color: var(--white, #f1f5f9);
  font-family: 'Space Grotesk', sans-serif;
  font-size: 0.95rem;
  line-height: 1.55;
  white-space: pre-wrap;
  word-break: break-word;
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
}

.bubble:hover {
  border-color: rgba(99, 102, 241, 0.38);
  box-shadow: 0 0 18px rgba(99, 102, 241, 0.08);
}

.timestamp {
  margin-top: 0.3rem;
  margin-right: 0.25rem;
  font-size: 0.7rem;
  color: rgba(241, 245, 249, 0.35);
  font-family: 'Space Grotesk', sans-serif;
}

'use client';

import { useState } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import s from './OmegaMessage.module.css';

/* ── Code block with copy button and dark inline theme ──────────── */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function CodeBlock({ inline, className, children, ...props }: any) {
  const lang = /language-(\w+)/.exec(className || '')?.[1];
  const [copied, setCopied] = useState(false);

  const copy = () => {
    navigator.clipboard.writeText(String(children).replace(/\n$/, ''));
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  if (!inline && lang) {
    return (
      <div className={s.codeWrap}>
        <div className={s.codeHeader}>
          <span className={s.codeLang}>{lang}</span>
          <button className={s.codeCopy} onClick={copy} aria-label="Copy code">
            {copied ? '✓ Copied' : 'Copy'}
